import 'dart:io'; import 'package:flutter/material.dart'; import 'package:sqflite/sqflite.dart'; import 'package:path/path.dart'; class OfflineDatabase { static Database? _database; Future<Database> get database async { if (_database != null) return _database!; _database = await initDB(); return _database!; } initDB() async { String path = join(await getDatabasesPath(), 'crisis_reports.db'); return await openDatabase(path, version: 1, onCreate: (db, version) async { await db.execute(''' CREATE TABLE reports ( id INTEGER PRIMARY KEY AUTOINCREMENT, danger_class INTEGER, latitude REAL, longitude REAL, timestamp TEXT, photo_path TEXT, synced INTEGER DEFAULT 0 ) '''); }); } Future<void> saveReport(int dangerClass, double lat, double lng, String photoPath) async { final db = await database; await db.insert('reports', { 'danger_class': dangerClass, 'latitude': lat, 'longitude': lng, 'timestamp': DateTime.now().toIso8601String(), 'photo_path': photoPath, 'synced': 0 }); } } class CrisisMapScreen extends StatelessWidget { final OfflineDatabase db = OfflineDatabase(); final List<Map<String, dynamic>> classes = [ {'level': 5, 'color': Colors.red, 'label': 'Класс 5: Заражение / Экстремально'}, {'level': 4, 'color': Colors.orange, 'label': 'Класс 4: Разрушение критических объектов'}, {'level': 3, 'color': Colors.yellow, 'label': 'Класс 3: Природная катастрофа / Ураган'}, {'level': 2, 'color': Colors.blue, 'label': 'Класс 2: Локальные повреждения'}, {'level': 1, 'color': Colors.green, 'label': 'Класс 1: Безопасно / Мониторинг'}, ]; @override Widget build(BuildContext context) { return Scaffold( appBar: AppBar(title: Text('CrisisMap5 - Сбор Данных')), body: ListView.builder( padding: EdgeInsets.all(16), itemCount: classes.length, itemBuilder: (context, index) { return Padding( padding: const EdgeInsets.symmetric(vertical: 8.0), child: ElevatedButton( style: ElevatedButton.styleFrom( backgroundColor: classes[index]['color'], minimumSize: Size(double.infinity, 80), ), onPressed: () async { await db.saveReport(classes[index]['level'], 41.311, 69.279, '/local/storage/img_${index}.jpg'); ScaffoldMessenger.of(context).showSnackBar( SnackBar(content: Text('Отчет класса ${classes[index]['level']} сохранен локально!')) ); }, child: Text(classes[index]['label'], style: TextStyle(fontSize: 18, color: Colors.white, fontWeight: FontWeight.bold)), ), ); }, ), ); } }
